// Pure helpers for matching Worker auction rows back to the current
// market snapshot. These are the domain rules that decide whether
// a given auction row from /seller-auctions corresponds to an item
// we already know about. Kept in their own module so the matching
// rules can be unit-tested without spinning up the MarketContext.

function normalizeItemLookup(value) {
  return String(value || "")
    .replace(/[\uE000-\uF8FF]/g, " ")
    .replace(/\s*\(t[123]\)\s*$/i, "")
    .replace(/^book:\s*/i, "")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
}

function rowLookupNames(row) {
  const baseKey = String(row.key || "").split("|")[0];
  return new Set([
    normalizeItemLookup(baseKey),
    normalizeItemLookup(row.name),
    normalizeItemLookup(row.rawName),
  ].filter(Boolean));
}

function auctionMatchesRow(auction, row) {
  if (!auction || !row) return false;
  const auctionTier = Number(auction.tier || 0);
  if (auctionTier > 0 && row.tier > 0 && auctionTier !== row.tier) return false;

  const variantKey = String(auction.variantKey || "").trim().toLowerCase();
  if (variantKey && !String(row.key || "").toLowerCase().includes(variantKey)) {
    return false;
  }

  const auctionNames = [
    auction.itemName,
    auction.setName && auction.itemName ? `${auction.setName} ${auction.itemName}` : "",
  ].map(normalizeItemLookup).filter(Boolean);
  const rowNames = rowLookupNames(row);
  return auctionNames.some((name) => rowNames.has(name));
}

function mapSellerAuctionsToItems(auctions, rows) {
  const matches = new Map();
  for (const auction of auctions || []) {
    let row = rows.find((candidate) => auctionMatchesRow(auction, candidate));
    if (!row && auction?.variantKey) {
      row = rows.find((candidate) => auctionMatchesRow({ ...auction, variantKey: "" }, candidate));
    }
    if (!row) continue;

    const existing = matches.get(row.key);
    const unitPrice = Number(auction.unitPrice || auction.price || 0);
    const timestamp = auction.timestamp ? new Date(auction.timestamp).getTime() : 0;
    if (existing) {
      existing.listingCount += 1;
      if (unitPrice > 0) {
        existing.minUnitPrice = Math.min(existing.minUnitPrice || unitPrice, unitPrice);
        existing.maxUnitPrice = Math.max(existing.maxUnitPrice || unitPrice, unitPrice);
      }
      existing.latestSeenMs = Math.max(existing.latestSeenMs || 0, timestamp || 0);
    } else {
      matches.set(row.key, {
        itemKey: row.key,
        listingCount: 1,
        minUnitPrice: unitPrice,
        maxUnitPrice: unitPrice,
        latestSeenMs: timestamp || 0,
      });
    }
  }
  return Array.from(matches.values());
}

export {
  normalizeItemLookup,
  rowLookupNames,
  auctionMatchesRow,
  mapSellerAuctionsToItems,
};
